return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var totalDots = 12;
    var dotRadius = 9;

    // Animation cycle (repeats every 9 seconds)
    var duration = 9000;
    var progress = (t % duration) / duration;

    var rows, cols, label;
    var phaseProgress;

    if (progress < 0.33) {
      rows = 1;
      cols = 12;
      label = '1 x 12 = 12';
      phaseProgress = progress / 0.33;
    } else if (progress < 0.66) {
      rows = 2;
      cols = 6;
      label = '2 x 6 = 12';
      phaseProgress = (progress - 0.33) / 0.33;
    } else {
      rows = 3;
      cols = 4;
      label = '3 x 4 = 12';
      phaseProgress = (progress - 0.66) / 0.34;
    }

    // Draw grid
    var startY = H / 2 - 15;
    var startX = W / 2;

    // Space between dots
    var dx = 32;
    var dy = 32;

    var gridWidth = (cols - 1) * dx;
    var gridHeight = (rows - 1) * dy;

    var originX = startX - gridWidth / 2;
    var originY = startY - gridHeight / 2;

    // Draw outline box around the grid (with fade-in on transition)
    ctx.strokeStyle = '#3B82F6';
    ctx.lineWidth = 2;
    var alpha = Math.min(1.0, phaseProgress * 3);
    ctx.globalAlpha = alpha;
    ctx.beginPath();
    ctx.roundRect(originX - dotRadius - 8, originY - dotRadius - 8, gridWidth + dotRadius * 2 + 16, gridHeight + dotRadius * 2 + 16, 8);
    ctx.stroke();
    ctx.globalAlpha = 1.0;

    // Draw dots
    for (var r = 0; r < rows; r++) {
      for (var c = 0; c < cols; c++) {
        var px = originX + c * dx;
        var py = originY + r * dy;

        // Subtle pulse for all dots
        var pulse = Math.sin(t * 0.005 + (r + c) * 0.3) * 1.5;

        ctx.fillStyle = '#EC4899'; // Coral dots
        ctx.beginPath();
        ctx.arc(px, py, dotRadius + pulse, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Draw Labels
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 20px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(label, W / 2, H - 40);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '14px -apple-system, sans-serif';
    ctx.fillText('Factors shown: ' + (rows === 1 ? '1, 12' : (rows === 2 ? '2, 6' : '3, 4')), W / 2, 40);
  }
};
